Функция РазделитьСтроку(ВходнаяСтрока, Разделитель)

	Результат = Новый Массив;
	Позиция = 1;
	Пока Позиция <= СтрДлина(ВходнаяСтрока) Цикл
		Найдено = Найти(ВходнаяСтрока, Разделитель, Позиция);
		Если Найдено = 0 Тогда
			Слово = Сред(ВходнаяСтрока, Позиция);
			Если СтрДлина(Слово) > 0 Тогда
				Результат.Добавить(Слово);
			КонецЕсли;
			Прервать;
		Иначе
			Слово = Сред(ВходнаяСтрока, Позиция, Найдено - Позиция);
			Если СтрДлина(Слово) > 0 Тогда
				Результат.Добавить(Слово);
			КонецЕсли;
			Позиция = Найдено + СтрДлина(Разделитель);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

