    // Приводим текст к нижнему регистру для игнорирования регистра
    Текст = НРег(Текст);

    // Разбиваем текст на слова, используя регулярное выражение.
    // Разделителем являются любые символы, кроме букв (латиница/кириллица), цифр и пробелов.
    Слова = СтрРазделить(Текст, "[^a-zA-Zа-яА-ЯёЁ0-9]+", , true);

    Результат = Новый Структура;

    Для Каждого Слово Из Слова Цикл
        // Проверяем, что слово не пустое (на случай двойных разделителей)
        Если ЗначениеЗаполнено(Слово) Тогда
            Если Результат.Свойство(Слово) Тогда
                // Увеличиваем счетчик, если слово уже есть в структуре
                Результат[Слово] = Результат[Слово] + 1;
            Иначе
                // Добавляем новое слово в структуру
                Результат.Вставить(Слово, 1);
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
