Функция ПодсчитатьСлова(ИсходнаяСтрока)
    // Инициализируем пустую структуру для хранения результатов
    СтруктураСлов = Новый Структура;

    // Преобразуем строку в нижний регистр
    ИсходнаяСтрока = СокрЛП(ИсходнаяСтрока.ToLower());

    // Разбиваем строку на слова
    МассивСлов = РазложитьСтрокуВМассив(ИсходнаяСтрока, " .,:;-!?");

    // Проходим по массиву слов
    Для Каждого Слово Из МассивСлов Цикл
        // Если слово уже есть в структуре, увеличиваем его счетчик
        Если СтруктураСлов.СодержитКлюч(Слово) Тогда
            СтруктураСлов[Слово] = СтруктураСлов[Слово] + 1;
        // Иначе добавляем слово в структуру с начальным значением 1
        Иначе
            СтруктураСлов.Вставить(Слово, 1);
        КонецЕсли;
    КонецЦикла;

    // Возвращаем структуру
    Возврат СтруктураСлов;
КонецФункции
