Функция ПосчитатьСлова(Текст)
    Экспорт

    // Создаем структуру для хранения результата
    Результат = Новый Структура;

    // Приводим текст к нижнему регистру и заменяем знаки препинания на пробелы
    Текст = НРег(Текст);
    Текст = СтрЗаменить(Текст, ".", " ");
    Текст = СтрЗаменить(Текст, ",", " ");
    Текст = СтрЗаменить(Текст, "!", " ");
    Текст = СтрЗаменить(Текст, "?", " ");
    Текст = СтрЗаменить(Текст, ":", " ");
    Текст = СтрЗаменить(Текст, ";", " ");

    // Разделяем текст на массив слов
    МассивСлов = СтрРазделить(Текст, " ");

    // Проходим по массиву и считаем количество каждого слова
    Для Каждого Слово Из МассивСлов Цикл
        Если Слово <> "" Тогда // Проверяем, чтобы не учитывать пустые строки
            Если Результат[Слово] = Неопределено Тогда
                Результат[Слово] = 1;
            Иначе
                Результат[Слово] = Результат[Слово] + 1;
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
