            КонецЕсли;
            Матрица[Инд1][Инд2] = Мин(
                Матрица[Инд1 - 1][Инд2] + 1,
                Матрица[Инд1][Инд2 - 1] + 1,
                Матрица[Инд1 - 1][Инд2 - 1] + Стоимость
            );
        КонецЦикла;
