Функция РедакционноеРасстояниеЛевенштейна(Строка1, Строка2)

	Длина1 = СтрДлина(Строка1);
	Длина2 = СтрДлина(Строка2);

	// Создаем матрицу для хранения расстояний
	// Размер матрицы (Длина1 + 1) x (Длина2 + 1)
	Матрица = Новый Массив(Длина1 + 1);
	Для i = 0 По Длина1 Цикл
		Матрица[i] = Новый Массив(Длина2 + 1);
	КонецЦикла;

	// Инициализация первой строки и первого столбца
	Для i = 0 По Длина1 Цикл
		Матрица[i][0] = i;
	КонецЦикла;
	Для j = 0 По Длина2 Цикл
		Матрица[0][j] = j;
	КонецЦикла;

	// Заполнение матрицы
	Для i = 1 По Длина1 Цикл
		Для j = 1 По Длина2 Цикл
			// Стоимость замены символа
			Если Сред(Строка1, i, 1) = Сред(Строка2, j, 1) Тогда
				СтоимостьЗамены = 0;
			Иначе
				СтоимостьЗамены = 1;
			КонецЕсли;

			// Вычисляем минимальное расстояние
			Матрица[i][j] = Минимальное(
				Матрица[i-1][j] + 1, // Удаление
				Матрица[i][j-1] + 1, // Вставка
				Матрица[i-1][j-1] + СтоимостьЗамены // Замена
			);
		КонецЦикла;
	КонецЦикла;

	// Результат находится в правом нижнем углу матрицы
	Возврат Матрица[Длина1][Длина2];

