Функция РедакционноеРасстояниеЛевенштейна(Стр1, Стр2)

	Длина1 = СтрДлина(Стр1);
	Длина2 = СтрДлина(Стр2);

	// Создаем массив для хранения расстояний
	Массив = Новый Массив(Длина1 + 1, Длина2 + 1);

	// Заполняем края массива
	Для i = 0 По Длина1 Цикл
		Массив[i, 0] = i;
	КонецЦикла;

	Для j = 0 По Длина2 Цикл
		Массив[0, j] = j;
	КонецЦикла;

	// Заполняем массив по формуле Левенштейна
	Для i = 1 По Длина1 Цикл
		Для j = 1 По Длина2 Цикл
			Если Сред(Стр1, i, 1) = Сред(Стр2, j, 1) Тогда
				Стоимость = 0;
			Иначе
				Стоимость = 1;
			КонецЕсли;

			Массив[i, j] = Мин(
				Массив[i-1, j] + 1,           // удаление
				Массив[i, j-1] + 1,           // вставка
				Массив[i-1, j-1] + Стоимость  // замена или совпадение
			);
		КонецЦикла;
	КонецЦикла;

	Возврат Массив[Длина1, Длина2];

