Функция Левенштейн(Строка1, Строка2)
	Если Строка1 = Строка2 Тогда
		Возврат 0;
	КонецЕсли;

	Размер1 = СтрДлина(Строка1);
	Размер2 = СтрДлина(Строка2);

	Матрица = Новый Массив;
	Для i = 0 По Размер1
		Матрица.Добавить(Новый Массив(Размер2));
		Для j = 0 По Размер2
			Матрица[i].Добавить(0);
		КонецЦикла;

	Для i = 0 По Размер1
		Матрица[i][0] = i;
	КонецЦикла;

	Для j = 0 По Размер2
		Матрица[0][j] = j;
	КонецЦикла;

	Для i = 1 По Размер1
		Для j = 1 По Размер2
			Стоимость = Если СтрПолучить(Строка1, i) = СтрПолучить(Строка2, j) Тогда 0 Иначе 1;
			Матрица[i][j] = Минимум(
				Матрица[i - 1][j] + 1, // удаление
				Матрица[i][j - 1] + 1, // вставка
				Матрица[i - 1][j - 1] + Стоимость // замена
			);
		КонецЦикла;
	КонецЦикла;

	Возврат Матрица[Размер1][Размер2];
КонецФункции
