Функция ПроверитьСбалансированностьСкобок(Строка) Экспорт
    Скобки = Новый Соответствие;
    Скобки["("] = ")";
    Скобки["["] = "]";
    Скобки["{"] = "}";

    Закрывающие = Новый Соответствие;
    Закрывающие[")"] = "(";
    Закрывающие["]"] = "[";
    Закрывающие["}"] = "{";

    Стек = Новый Массив;

    Для i = 1 По СтрДлина(Строка) Цикл
        Символ = Сред(Строка, i, 1);

        Если Скобки.СодержитКлюч(Символ) Тогда
            Стек.Добавить(Символ);
        ИначеЕсли Закрывающие.СодержитКлюч(Символ) Тогда
            Если Стек.Количество() = 0 Тогда
                Возврат Ложь;
            КонецЕсли;

            ПоследняяОткрывающая = Стек[Стек.Количество() - 1];
            Если ПоследняяОткрывающая <> Закрывающие[Символ] Тогда
                Возврат Ложь;
            КонецЕсли;

            Стек.Удалить(Стек.Количество() - 1);
        КонецЕсли;
    КонецЦикла;

    Возврат Стек.Количество() = 0;
КонецФункции
