Функция СкобкиСбалансированы(Строка) Экспорт
    Стек = Новый Массив;
    Для Номер = 1 По СтрДлина(Строка) Цикл
        Символ = Сред(Строка, Номер, 1);
        Если Символ = "(" ИЛИ Символ = "[" ИЛИ Символ = "{" Тогда
            Стек.Добавить(Символ);
        ИначеЕсли Символ = ")" Тогда
            Если Стек.Количество() = 0 ИЛИ Стек[Стек.ВГраница()] <> "(" Тогда
                Возврат Ложь;
            КонецЕсли;
            Стек.Удалить(Стек.ВГраница());
        ИначеЕсли Символ = "]" Тогда
            Если Стек.Количество() = 0 ИЛИ Стек[Стек.ВГраница()] <> "[" Тогда
                Возврат Ложь;
            КонецЕсли;
            Стек.Удалить(Стек.ВГраница());
        ИначеЕсли Символ = "}" Тогда
            Если Стек.Количество() = 0 ИЛИ Стек[Стек.ВГраница()] <> "{" Тогда
                Возврат Ложь;
            КонецЕсли;
            Стек.Удалить(Стек.ВГраница());
        КонецЕсли;
    КонецЦикла;
    Возврат Стек.Количество() = 0;
КонецФункции

Функция ПроверитьСкобки(Строка)
	Стек = Новый Массив;
	Для Каждого Символ Из СтрокаВСимволы(Строка) Цикл
		Если Символ = "(" Тогда
			Стек.Добавить(Символ);
		ИначеЕсли Символ = "[" Тогда
			Стек.Добавить(Символ);
		ИначеЕсли Символ = "{" Тогда
			Стек.Добавить(Символ);
		ИначеЕсли Символ = ")" Тогда
			Если Стек.Количество() = 0 Или Стек[Стек.Количество() - 1] <> "(" Тогда
				Возврат Ложь;
			КонецЕсли;
			Стек.Удалить(Стек.Количество() - 1);
		ИначеЕсли Символ = "]" Тогда
			Если Стек.Количество() = 0 Или Стек[Стек.Количество() - 1] <> "[" Тогда
				Возврат Ложь;
			КонецЕсли;
			Стек.Удалить(Стек.Количество() - 1);
