    ТекА = А;
    ТекБ = Б;
    Пока ТекБ <> 0 Цикл
        Врем = ТекБ;
        ТекБ = ТекА % ТекБ;
        ТекА = Врем;
    КонецЦикла;
    НОД = ТекА;

    // Вычисление НОК по формуле: НОК = (А * Б) / НОД
    НОК = (А * Б) / НОД;

    // Формирование структуры результата
