Функция ПолучитьПростыеЧисла(Граница) Экспорт
    Если Граница < 2 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    МассивПростых = Новый Массив;
    МассивФлагов = Новый Массив(Граница + 1);

    Для Инд = 0 По Граница Цикл
        МассивФлагов[Инд] = Истина;
    КонецЦикла;

    МассивФлагов[0] = Ложь;
    Если Граница >= 1 Тогда
        МассивФлагов[1] = Ложь;
    КонецЕсли;

    Для Инд = 2 По Цел(Sqrt(Граница)) Цикл
        Если МассивФлагов[Инд] Тогда
            Для Дж = Инд * Инд По Граница Шаг Инд Цикл
                МассивФлагов[Дж] = Ложь;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;

    Для Инд = 2 По Граница Цикл
        Если МассивФлагов[Инд] Тогда
            МассивПростых.Добавить(Инд);
        КонецЕсли;
    КонецЦикла;

    Возврат МассивПростых;
