		Возврат Новый Массив;
	КонецЕсли;

	// Создаем булев массив, где индекс соответствует числу.
	// Изначально считаем все числа простыми.
	// Размер массива на 1 больше границы, чтобы индексы соответствовали числам.
	Простые = Новый Массив(Граница + 1);
	Для Индекс = 0 По Граница Цикл
		Простые[Индекс] = Истина;
	КонецЦикла;

	// 0 и 1 не являются простыми числами
	Простые[0] = Ложь;
	Простые[1] = Ложь;

	// Решето Эратосфена
	Для Число = 2 Поsqrt(Граница) Цикл
		Если Простые[Число] = Истина Тогда
			// Если число простое, вычеркиваем все его кратные
			Для Кратное = Число * Число По Граница Шаг Число Цикл
				Простые[Кратное] = Ложь;
			КонецЦикла;
		КонецЕсли;
	КонецЦикла;

	// Собираем массив простых чисел
	Результат = Новый Массив;
	Для Индекс = 2 По Граница Цикл
		Если Простые[Индекс] = Истина Тогда
			Результат.Добавить(Индекс);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

