Функция ПростыеЧислаДоГраницы(Граница)

	Если Границa < 2 Тогда
		Возврат [];
	КонецЕсли;

	// Создаем массив флагов
	Флаги = ?(Граница >= 0, Новый Массив(Граница + 1), Новый Массив());
	Для i = 0 По Граница Цикл
		Флаги[i] = Истина;
	КонецЦикла;

	Флаги[0] = Ложь;
	Если Граница >= 1 Тогда
		Флаги[1] = Ложь;
	КонецЕсли;

	Для i = 2 По Цел(Корень(Граница)) Цикл
		Если Флаги[i] Тогда
			Для j = i * i По Граница Цикл j = j + i
				Флаги[j] = Ложь;
			КонецЦикла;
		КонецЕсли;
	КонецЦикла;

	Результат = Новый Массив();
	Для i = 2 По Граница Цикл
		Если Флаги[i] Тогда
			Результат.Добавить(i);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

