Функция ЦиклическийСдвигМассива(Массив, Сдвиг)

	Если Массив = Неопределено Или Массив.Количество() = 0 Тогда
		Возврат Новый Массив;
	КонецЕсли;

	ДлинаМассива = Массив.Количество();

	// Приводим сдвиг к диапазону [0, ДлинаМассива - 1]
	НормализованныйСдвиг = Сдвиг % ДлинаМассива;
	Если НормализованныйСдвиг < 0 Тогда
		НормализованныйСдвиг = НормализованныйСдвиг + ДлинаМассива;
	КонецЕсли;

	Если НормализованныйСдвиг = 0 Тогда
		Возврат Массив.Скопировать(); // Возвращаем копию, если сдвиг нулевой
	КонецЕсли;

	НовыйМассив = Новый Массив(ДлинаМассива);

	Для Индекс = 0 По ДлинаМассива - 1 Цикл
		НовыйИндекс = (Индекс + НормализованныйСдвиг) % ДлинаМассива;
		НовыйМассив[НовыйИндекс] = Массив[Индекс];
	КонецЦикла;

	Возврат НовыйМассив;

КонецФункции
