Функция ЦиклическийСдвиг(Массив, Сдвиг)
    Если Массив.Количество() = 0 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    ДлинаМассива = Массив.Количество();
    Сдвиг = Сдвиг % ДлинаМассива;
    Если Сдвиг < 0 Тогда
        Сдвиг = ДлинаМассива + Сдвиг;
    КонецЕсли;

    НовыйМассив = Новый Массив;
    Для i = 0 По ДлинаМассива - 1 Цикл
        ИндексИсходного = (i - Сдвиг + ДлинаМассива) % ДлинаМассива;
        НовыйМассив.Добавить(Массив[ИндексИсходного]);
    КонецЦикла;

    Возврат НовыйМассив;
КонецФункции

Функция СдвинутьМассивВправо(Массив, Сдвиг)
    Если Массив.Количество() = 0 Тогда
        Возврат Новый Массив();
    КонецЕсли;

    Длина = Массив.Количество();
    ЭффективныйСдвиг = Сдвиг % Длина;

    Если ЭффективныйСдвиг = 0 Тогда
        Возврат Массив.Скопировать();
    КонецЕсли;

    // Берем хвост (последние ЭффективныйСдвиг элементов)
    Хвост = Массив.Скопировать(Длина - ЭффективныйСдвиг, ЭффективныйСдвиг);
    // Берем голову (оставшиеся элементы)
    Голова = Массив.Скопировать(0, Длина - ЭффективныйСдвиг);

    // Объединяем хвост и голову
    Возврат Хвост.Объединить(Голова);
КонецФункции

