Функция ЦиклическийСдвигМассива(ИсходныйМассив, Сдвиг)
	Если ИсходныйМассив = Неопределено Или ИсходныйМассив.Количество() = 0 Тогда
		Возврат Новый Массив;
	КонецЕсли;

	ДлинаМассива = ИсходныйМассив.Количество();
	Сдвиг = Сдвиг % ДлинаМассива;

	Если Сдвиг > 0 Тогда
		Возврат ИсходныйМассив.ПолучитьЧасть(ДлинаМассива - Сдвиг, ДлинаМассива) + ИсходныйМассив.ПолучитьЧасть(0, ДлинаМассива - Сдвиг);
	Иначе
		Возврат ИсходныйМассив.ПолучитьЧасть(-Сдвиг, ДлинаМассива) + ИсходныйМассив.ПолучитьЧасть(ДлинаМассива + Сдвиг, ДлинаМассива);
	КонецЕсли;
КонецФункции
