Функция РазобратьФИО(СтрокаФИО)

	Результат = Новый Структура;
	Результат.Вставить("Фамилия", "");
	Результат.Вставить("Имя", "");
	Результат.Вставить("Отчество", "");
	Результат.Вставить("Инициалы", "");
	Результат.Вставить("ФИОКраткое", "");

	МассивЧастей = СтрРазделить(СтрокаФИО, " ");

	Если МассивЧастей.Количество() = 0 Тогда
		Возврат Результат;
	КонецЕсли;

	// Фамилия всегда первая
	Результат.Фамилия = МассивЧастей[0];

	Если МассивЧастей.Количество() > 1 Тогда
		// Имя второе
		Результат.Имя = МассивЧастей[1];
	КонецЕсли;

	Если МассивЧастей.Количество() > 2 Тогда
		// Отчество - все оставшиеся части
		Результат.Отчество = СтрСоединить(МассивЧастей, " ", 2);
	КонецЕсли;

	// Формирование инициалов
	Инициалы = "";
	Если Результат.Имя <> "" Тогда
		Инициалы = Лев(Результат.Имя, 1) + ".";
	КонецЕсли;
	Если Результат.Отчество <> "" Тогда
		Инициалы = Инициалы + Лев(Результат.Отчество, 1) + ".";
	КонецЕсли;
	Результат.Инициалы = Инициалы;

	// Формирование ФИОКраткое
	Если Результат.Фамилия <> "" Тогда
		Результат.ФИОКраткое = Результат.Фамилия + " " + Результат.Инициалы;
	ИначеЕсли Результат.Имя <> "" Тогда
		Результат.ФИОКраткое = Результат.Имя + " " + Результат.Инициалы;
	ИначеЕсли Результат.Отчество <> "" Тогда
		Результат.ФИОКраткое = Результат.Отчество + " " + Результат.Инициалы;
	КонецЕсли;

	Возврат Результат;

КонецФункции
