Функция ПарситьФИО(СтрокаФИО)

    СтрокаФИО = СокрЛП(СтрокаФИО);
    Части = СтрРазделить(СтрокаФИО, " ", Ложь);
    КоличествоЧастей = Части.Количество();

    СтруктураРезультат = Новый Структура("Фамилия, Имя, Отчество, Инициалы, ФИОКраткое", "", "", "", "", "");

    Если КоличествоЧастей >= 3 Тогда
        СтруктураРезультат.Фамилия = Части[0];
        СтруктураРезультат.Имя = Части[1];
        СтруктураРезультат.Отчество = Части[2];
        Инициалы = Лев(Части[1], 1) + "." + Лев(Части[2], 1) + ".";
    ИначеЕсли КоличествоЧастей = 2 Тогда
        СтруктураРезультат.Фамилия = Части[0];
        СтруктураРезультат.Имя = Части[1];
        СтруктураРезультат.Отчество = "";
        Инициалы = Лев(Части[1], 1) + ".";
    Иначе
        СтруктураРезультат.Фамилия = Части[0];
        СтруктураРезультат.Имя = "";
        СтруктураРезультат.Отчество = "";
        Инициалы = "";
    КонецЕсли;

    СтруктураРезультат.Инициалы = Инициалы;

    Если ПустаяСтрока(СтруктураРезультат.Фамилия) Тогда
        СтруктураРезультат.ФИОКраткое = "";
    ИначеЕсли ПустаяСтрока(СтруктураРезультат.Имя) Тогда
        СтруктураРезультат.ФИОКраткое = СтруктураРезультат.Фамилия;
    Иначе
        СтруктураРезультат.ФИОКраткое = СтруктураРезультат.Фамилия + " " + Инициалы;
    КонецЕсли;

    Возврат СтруктураРезультат;

КонецФункции

