		СтруктураРезультат.Отчество = Поля[2];
	КонецЕсли;

	Инициалы = "";
	Если СтруктураРезультат.Имя <> "" Тогда
		Инициалы = Сред(СтруктураРезультат.Имя, 1, 1) + ".";
	КонецЕсли;

	Если СтруктураРезультат.Отчество <> "" Тогда
		Инициалы = Инициалы + Сред(СтруктураРезультат.Отчество, 1, 1) + ".";
	КонецЕсли;

	СтруктураРезультат.Инициалы = Инициалы;

	ФИОКраткое = СтруктураРезультат.Фамилия;
	Если Инициалы <> "" Тогда
		ФИОКраткое = ФИОКраткое + " " + Инициалы;
	КонецЕсли;

	СтруктураРезультат.ФИОКраткое = ФИОКраткое;

	Возврат СтруктураРезультат;
КонецФункции

Функция РазложитьФИО(Знач СтрокаФИО) Экспорт

    Результат = Новый Структура;

    // Разбиваем строку на части по пробелам
    Части = СтрРазделить(СокрЛП(СтрокаФИО), " ", Ложь);

    // Фамилия (всегда первая часть)
    Если Части.Количество() >= 1 Тогда
        Результат.Вставить("Фамилия", СокрЛП(Части[0]));
    Иначе
        Результат.Вставить("Фамилия", "");
    КонецЕсли;

    // Имя (вторая часть)
    Если Части.Количество() >= 2 Тогда
        Результат.Вставить("Имя", СокрЛП(Части[1]));
    Иначе
        Результат.Вставить("Имя", "");
    КонецЕсли;

    // Отчество (третья часть)
    Если Части.Количество() >= 3 Тогда
        Результат.Вставить("Отчество", СокрЛП(Части[2]));
    Иначе
        Результат.Вставить("Отчество", "");
    КонецЕсли;

    // Инициалы
    Инициалы = "";
    Если Результат.Имя <> "" Тогда
        Инициалы = Лев(Результат.Имя, 1) + ".";
    КонецЕсли;
    Если Результат.Отчество <> "" Тогда
        Инициалы = Инициалы + Лев(Результат.Отчество, 1) + ".";
    КонецЕсли;
    Результат.Вставить("Инициалы", Инициалы);

    // ФИО Краткое
    ФИОКраткое = "";
    Если Результат.Имя <> "" Тогда
        ФИОКраткое = Результат.Фамилия + " " + Лев(Результат.Имя, 1) + ".";
        Если Результат.Отчество <> "" Тогда
            ФИОКраткое = ФИОКраткое + Лев(Результат.Отчество, 1) + ".";
        КонецЕсли;
    Иначе
        ФИОКраткое = Результат.Фамилия;
    КонецЕсли;
    Результат.Вставить("ФИОКраткое", ФИОКраткое);

    Возврат Результат;

