Функция ПарситьJSON(СтрокаJSON) Экспорт

    Поз = 1;
    Значение = РазобратьЗначение(СтрокаJSON, Поз);

    Если Значение = Неопределено Тогда
        Возврат Неопределено;
    КонецЕсли;

    // проверяем, что после разбора только пробелы
    ПропуститьПробелы(СтрокаJSON, Поз);
    Если Поз <= СтрДлина(СтрокаJSON) Тогда
        Возврат Неопределено;
    КонецЕсли;

    Возврат Значение;

КонецФункции

// Вспомогательная функция пропуска пробелов
Процедура ПропуститьПробелы(Стр, Поз)
    Пока Поз <= СтрДлина(Стр) Цикл
        Символ = Сред(Стр, Поз, 1);
        Если Символ = " " Или Символ = Символы.ПС Или Символ = Символы.ВК Или Символ = Символы.Таб Тогда
            Поз = Поз + 1;
        Иначе
            Прервать;
        КонецЕсли;
    КонецЦикла;
КонецПроцедуры

// Разбор значения (любой тип)
Функция РазобратьЗначение(Стр, Поз)

    ПропуститьПробелы(Стр, Поз);
    Если Поз > СтрДлина(Стр) Тогда
        Возврат Неопределено;
    КонецЕсли;

    Символ = Сред(Стр, Поз, 1);

    Если Символ = "{" Тогда
        Возврат РазобратьОбъект(Стр, Поз);
    ИначеЕсли Символ = "[" Тогда
        Возврат РазобратьМассив(Стр, Поз);
    ИначеЕсли Символ = """" Тогда
        Возврат РазобратьСтроку(Стр, Поз);
    ИначеЕсли Символ = "t" Или Символ = "f" Или Символ = "n" Тогда
        Возврат РазобратьЛитерал(Стр, Поз);
    Иначе
        // предполагаем число
        Возврат РазобратьЧисло(Стр, Поз);
    КонецЕсли;

КонецФункции

// Разбор строки
Функция РазобратьСтроку(Стр, Поз)
    // предполагаем, что текущий символ - кавычка
    Поз = Поз + 1; // пропускаем "
    Результат = "";
    Пока Поз <= СтрДлина(Стр) Цикл
        Символ = Сред(Стр, Поз, 1);
        Если Символ = """" Тогда
            Поз = Поз + 1;
            Возврат Результат;
        ИначеЕсли Символ = "\" Тогда
            // экранирование
            Поз = Поз + 1;
            Если Поз > СтрДлина(Стр) Тогда
                Возврат Неопределено;
            КонецЕсли;
            СимволЭкр = Сред(Стр, Поз, 1);
            Если СимволЭкр = """" Тогда
                Результат = Результат + """";
            ИначеЕсли СимволЭкр = "\" Тогда
                Результат = Результат + "\";
            ИначеЕсли СимволЭкр = "/" Тогда
                Результат = Результат + "/";
            ИначеЕсли СимволЭкр = "b" Тогда
                Результат = Результат + Символ(8); // backspace
            ИначеЕсли СимволЭкр = "f" Тогда
                Результат = Результат + Символ(12); // form feed
            ИначеЕсли СимволЭкр = "n" Тогда
                Результат = Результат + Символ(10); // new line
            ИначеЕсли СимволЭкр = "r" Тогда
                Результат = Результат + Символ(13); // carriage return
            ИначеЕсли СимволЭкр = "t" Тогда
                Результат = Результат + Символ(9); // tab
            Иначе
                // неизвестная последовательность - ошибка
                Возврат Неопределено;
            КонецЕсли;
            Поз = Поз + 1;
        Иначе
            Результат = Результат + Символ;
            Поз = Поз + 1;
        КонецЕсли;
    КонецЦикла;
    // кавычка не найдена
    Возврат Неопределено;
КонецФункции

// Разбор числа
Функция РазобратьЧисло(Стр, Поз)
    НачалоПоз = Поз;
    Если Поз <= СтрДлина(Стр) И Сред(Стр, Поз, 1) = "-" Тогда
        Поз = Поз + 1;
    КонецЕсли;

    // целая часть
    Если Поз <= СтрДлина(Стр) И Сред(Стр, Поз, 1) = "0" Тогда
        Поз = Поз + 1;
    ИначеЕсли Поз <= СтрДлина(Стр) И (Сред(Стр, Поз, 1) >= "1" И Сред(Стр, Поз, 1) <= "9") Тогда
        Поз = Поз + 1;
        Пока Поз <= СтрДлина(Стр) И (Сред(Стр, Поз, 1) >= "0" И Сред(Стр, Поз, 1) <= "9") Цикл
            Поз = Поз + 1;
        КонецЦикла;
    Иначе
        // нет цифр - ошибка
        Возврат Неопределено;
    КонецЕсли;

    // дробная часть
    Если Поз <= СтрДлина(Стр) И Сред(Стр, Поз, 1) = "." Тогда
        Поз = Поз + 1;
        Если Поз > СтрДлина(Стр) Или Сред(Стр, Поз, 1) < "0" Или Сред(Стр, Поз, 1) > "9" Тогда
            Возврат Неопределено;
        КонецЕсли;
        Пока Поз <= СтрДлина(Стр) И (Сред(Стр, Поз, 1) >= "0" И Сред(Стр, Поз, 1) <= "9") Цикл
            Поз = Поз + 1;
        КонецЦикла;
    КонецЕсли;

    // экспонента
    Если Поз <= СтрДлина(Стр) И (Сред(Стр, Поз, 1) = "e" Или Сред(Стр, Поз, 1) = "E") Тогда
        Поз = Поз + 1;
        Если Поз <= СтрДлина(Стр) И (Сред(Стр, Поз, 1) = "+" Или Сред(Стр, Поз, 1) = "-") Тогда
            Поз = Поз + 1;
        КонецЕсли;
        Если Поз > СтрДлина(Стр) Или Сред(Стр, Поз, 1) < "0" Или Сред(Стр, Поз, 1) > "9" Тогда
            Возврат Неопределено;
        КонецЕсли;
        Пока Поз <= СтрДлина(Стр) И (Сред(Стр, Поз, 1) >= "0" И Сред(Стр, Поз, 1) <= "9") Цикл
            Поз = Поз + 1;
        КонецЦикла;
    КонецЕсли;

    ЧастьСтроки = Сред(Стр, НачалоПоз, Поз - НачалоПоз);
    Попытка
        ЧислоРез = Число(ЧастьСтроки);
    Исключение
        Возврат Неопределено;
    КонецПопытки;

    Возврат ЧислоРез;

КонецФункции

// Разбор литералов true, false, null
Функция РазобратьЛитерал(Стр, Поз)
    Если Сред(Стр, Поз, 4) = "true" Тогда
        Поз = Поз + 4;
        Возврат Истина;
    ИначеЕсли Сред(Стр, Поз, 5) = "false" Тогда
        Поз = Поз + 5;
        Возврат Ложь;
    ИначеЕсли Сред(Стр, Поз, 4) = "null" Тогда
        Поз = Поз + 4;
        Возврат Неопределено; // null соответствует Неопределено в 1С
    Иначе
        Возврат Неопределено;
    КонецЕсли;
КонецФункции

// Разбор объекта (структуры)
Функция РазобратьОбъект(Стр, Поз)
    Поз = Поз + 1; // пропускаем {
    ПропуститьПробелы(Стр, Поз);
    Результат = Новый Структура;

    Если Поз <= СтрДлина(Стр) И Сред(Стр, Поз, 1) = "}" Тогда
        Поз = Поз + 1;
        Возврат Результат;
    КонецЕсли;

    Пока Истина Цикл
        ПропуститьПробелы(Стр, Поз);
        // ожидаем строку ключа
        Если Поз > СтрДлина(Стр) Или Сред(Стр, Поз, 1) <> """" Тогда
