Функция ПроверитьИНН(ИНН)

	Если НЕ ТипЗнч(ИНН) = Тип("Строка") И НЕ ТипЗнч(ИНН) = Тип("Число") Тогда
		Возврат Ложь;
	КонецЕсли;

	ИНН = Строка(ИНН);

	// Проверка на пустую строку
	Если СтрДлина(ИНН) = 0 Тогда
		Возврат Ложь;
	КонецЕсли;

	// Проверка на наличие только цифр
	Для Счетчик = 1 По СтрДлина(ИНН) Цикл
		Символ = Сред(ИНН, Счетчик, 1);
		Если НЕ Символ >= "0" И НЕ Символ <= "9" Тогда
			Возврат Ложь;
		КонецЕсли;
	КонецЦикла;

	// Проверка длины
	Если СтрДлина(ИНН) <> 10 И СтрДлина(ИНН) <> 12 Тогда
		Возврат Ложь;
	КонецЕсли;

	// Проверка контрольных цифр
	Если СтрДлина(ИНН) = 10 Тогда
		// Алгоритм для 10-значного ИНН
		Сумма = 0;
		Для Счетчик = 1 По 9 Цикл
			Сумма = Сумма + Сред(ИНН, Счетчик, 1) * (11 - Счетчик);
		КонецЦикла;
		КонтрольнаяЦифра = (Сумма % 11) % 10;
		Если Сред(ИНН, 10, 1) <> Строка(КонтрольнаяЦифра) Тогда
			Возврат Ложь;
		КонецЕсли;
	ИначеЕсли СтрДлина(ИНН) = 12 Тогда
		// Алгоритм для 12-значного ИНН
		// Первая контрольная цифра
		Сумма1 = 0;
		Для Счетчик = 1 По 10 Цикл
			Сумма1 = Сумма1 + Сред(ИНН, Счетчик, 1) * (11 - Счетчик);
		КонецЦикла;
		КонтрольнаяЦифра1 = (Сумма1 % 11) % 10;
		Если Сред(ИНН, 11, 1) <> Строка(КонтрольнаяЦифра1) Тогда
			Возврат Ложь;
		КонецЕсли;

		// Вторая контрольная цифра
		Сумма2 = 0;
		Для Счетчик = 1 По 10 Цикл
			Сумма2 = Сумма2 + Сред(ИНН, Счетчик, 1) * (12 - Счетчик);
		КонецЦикла;
		КонтрольнаяЦифра2 = (Сумма2 % 11) % 10;
		Если Сред(ИНН, 12, 1) <> Строка(КонтрольнаяЦифра2) Тогда
			Возврат Ложь;
		КонецЕсли;
	КонецЕсли;

	Возврат Истина;

КонецФункции
