Функция ПроверкаИНН(ИНН) Экспорт
	// Проверка, что ИНН — строка, не пустая и состоит только из цифр
	Если Не ТипЗнч(ИНН) = Тип("Строка") Тогда
		Возврат Ложь;
	КонецЕсли;

	Если СтрДлина(ИНН) = 0 Тогда
		Возврат Ложь;
	КонецЕсли;

	Если Не РегулярноеВыражение("^\d+$").Совпадение(ИНН) Тогда
		Возврат Ложь;
	КонецЕсли;

	Длина = СтрДлина(ИНН);

	// Проверка длины: только 10 или 12
	Если Длина <> 10 И Длина <> 12 Тогда
		Возврат Ложь;
	КонецЕсли;

	// Преобразуем строку в массив чисел
	Цифры = Новый Массив(Длина);
	Для i = 0 По Длина - 1 Цикл
		Цифры[i] = ?(СтрЧисло(Сред(ИНН, i + 1, 1)), 0);
	КонецЦикла;

	// Проверка для юридического лица (10 знаков)
	Если Длина = 10 Тогда
		Коэффициенты = [2, 4, 10, 3, 5, 9, 4, 6, 8];
		Сумма = 0;
		Для i = 0 По 8 Цикл
			Сумма = Сумма + Цифры[i] * Коэффициенты[i];
		КонецЦикла;
		Контрольная = Сумма % 11;
		Если Контрольная > 9 Тогда
			Контрольная = Контрольная % 10;
		КонецЕсли;
		Возврат Контрольная = Цифры[9];
	Иначе // Длина = 12 — физическое лицо или ИП
		// Первая контрольная цифра
		Коэффициенты1 = [7, 2, 4, 10, 3, 5, 9, 4, 6, 8];
		Сумма1 = 0;
		Для i = 0 По 10 Цикл
			Сумма1 = Сумма1 + Цифры[i] * Коэффициенты1[i];
		КонецЦикла;
		Контрольная1 = Сумма1 % 11;
		Если Контрольная1 > 9 Тогда
			Контрольная1 = Контрольная1 % 10;
		КонецЕсли;

		// Вторая контрольная цифра
		Коэффициенты2 = [3, 7, 2, 4, 10, 3, 5, 9, 4, 6, 8];
		Сумма2 = 0;
		Для i = 0 По 10 Цикл
			Сумма2 = Сумма2 + Цифры[i] * Коэффициенты2[i];
		КонецЦикла;
		Контрольная2 = Сумма2 % 11;
		Если Контрольная2 > 9 Тогда
			Контрольная2 = Контрольная2 % 10;
		КонецЕсли;

		Возврат Контрольная1 = Цифры[10] И Контрольная2 = Цифры[11];
	КонецЕсли;
КонецФункции

Функция ПроверитьИНН(Знач СтрИНН)
    // Проверка на пустую строку
    Если СтрДлина(СтрИНН) = 0 Тогда
        Возврат Ложь;
    КонецЕсли;

    // Проверка на наличие нецифровых символов
    Если СтрНайти(СтрИНН, "[^0-9]") <> "" Тогда
        Возврат Ложь;
    КонецЕсли;

    // Проверка длины
    Если СтрДлина(СтрИНН) <> 10 И СтрДлина(СтрИНН) <> 12 Тогда
        Возврат Ложь;
    КонецЕсли;

    // Логика для 10-значного ИНН
    Если СтрДлина(СтрИНН) = 10 Тогда
        Веса = Новый Массив;
        Веса.Добавить(2); Веса.Добавить(4); Веса.Добавить(10); Веса.Добавить(3); Веса.Добавить(5);
        Веса.Добавить(9); Веса.Добавить(4); Веса.Добавить(6); Веса.Добавить(8);

        СуммаВеса = 0;
        Для к = 1 По 9 Цикл
            СуммаВеса = СуммаВеса + Число(Сред(СтрИНН, к, 1)) * Веса[к-1];
        КонецЦикла;

        Проверочный = СуммаВеса % 11;
        Если Проверочный = 10 Тогда
            Проверочный = 0;
        КонецЕсли;

        Возврат Число(Сред(СтрИНН, 10, 1)) = Проверочный;

    // Логика для 12-значного ИНН
    ИначеЕсли СтрДлина(СтрИНН) = 12 Тогда
        Веса1 = Новый Массив;
        Веса1.Добавить(7); Веса1.Добавить(2); Веса1.Добавить(4); Веса1.Добавить(10); Веса1.Добавить(3);
        Веса1.Добавить(5); Веса1.Добавить(9); Веса1.Добавить(4); Веса1.Добавить(6); Веса1.Добавить(8);

